footer:{adress1:"Buxoro viloyati Kogon tumani B.Naqshband MFY Abay ko'chasi 20-uy",adress2:"Buxoro shahri Sitorayi Mohi-Xosa MFY G'ijduvon ko'chasi 250-uy",menu_title1:"Vakansiya",menu_title2:"Kabinetga kirish",menu_title3:"Onlayn qabul",menu1_link1:"Universitet ma'lumotlari",menu1_link2:"Ta'lim sohalari",menu1_link3:"Mashg'ulot kurslari",menu1_link4:"Ta'lim narxi",menu1_link5:"Sayt xaritasi",menu2_link1:"Kirish so'zi",menu2_link2:"Maqsad, vazifa, qadriyat",menu2_link3:"Ramzlar",menu2_link4:"Kontaktlar va fikr-mulohazalar",menu2_link5:"Grantlar va stipendiyalar",copyright:"Mualliflik huquqi \xa9 2024. BuxPXTI. Barcha huquqlar himoyalangan"},welcome_speech:{title:"Kirish so'zi",descr:"Oliygoh ta`sischisi B SH.R. ",title1:"Oliygoh ta`sischisi",title2:"Buxoro psixologiya va xorijiy tillar institutiga xush kelibsiz!",text1:"Baratov Sharif Ramazonovich 1960-yil 22-martda Buxoro viloyati, Kogon tumani  ziyolilar oilasida tavallud topgan. ",text2:"Ma\u2019lumoti oliy, Buxoro Davlat pedagogika instituti talabasi sifatida  1979-1983-yillarda tahsil olgan. 1987-1990-yillarda O\u02bbzbekiston Respublikasi Fanlar akademiyasi aspiranti.  ",text3:"Faoliyati davomida: 1999-1999-yillar Buxoro Davlat universiteti ilmiy ishlar bo\u02bbyicha prorektori. 1999-2002 yillar Buxoro Davlat universiteti psixologiya kafedrasi mudiri. 2002-2005 yillar Respublika Ma'naviyat va ma'rifat markazi Buxoro viloyat bo\u02bblimi rahbari. 2005-2011 yillar Buxoro Davlat universiteti psixologiya kafedrasi mudiri. 2011-2017 yillar Buxoro Davlat universiteti pedagogika fakulteti dekani. 2017-2021 yillar Buxoro Davlat universiteti psixologiya kafedrasi mudiri. 2021-2022 yillar Buxoro Davlat universiteti psixologiya kafedrasi professori. 2021 yildan Buxoro psixologiya va xorijiy tillar instituti rektori.",text4:"",text5:" O\u2019zbekiston Respublikasi \nPrezidenti Sh.M.Mirziyoyevning 2021 yil 21-22 yanvar kunlari Buxoro \nviloyatiga tashrifi davomida va Xalq deputatlari viloyat kengashining \nnavbatdan tashqari sessiyasida bergan topshiriqlari ijrosini ta\u2019minlash \nbo\u2019yicha shakllantirilgan 4-sonli bayonnomaning 98-bandiga asosan tashkil \netilgan.\nBuxoro psixologiya va xorijiy tillar instituti O\u2019zbekiston Respublikasi Vazirlar \nMahkamasi huzuridagi ta\u2019lim sifatini nazorat qilish davlat inspeksiyasi \ntomonidan taqdim etilgan \u2116432747-sonli litsenziyasi asosida faoliyat \nyuritmoqda. ( Insitut 2021-yildan tashkil etilgan)\n"},campuses:{title:"Kampuslar",descr:"Universitetning Buxoro va Samarqand kampuslari mavjud ",tab1_btn:"Buxoro",tab2_btn:"Samarqand",card_title1:"Buxoro kampusi loyihasi",card_title2:"Samarqand kampusi loyihasi",card_item1:"Umumiy maydoni",card_item2:"Bloklar soni",card_item3:"Auditoriyalar",card_item4:"Parkovka",card_item5:"Yotoqxona",card_item6:"Eko-zona",title_secondary:"Kampus xaritasi",map_item1:"Asosiy kampus",map_item2:"Faollar zali ostidagi blok",map_item3:"Sportzal ostidagi blok",map_item4:"Tibbiy korpus (qurilmoqda)",map_item5:"Rektorat binosi (qurilmoqda)",map_item6:"Avtomobil turargohi",map_item7:"Eko-zonalar",data1:" ga",data2:" ta",data3:" ta",data4:" ta auto",data5:"o'rinli",data6:"mavjud"},purpose:{title:"Maqsad, Vazifa, Qadriyat",card1_title:"Maqsad",card1_text:"ZARMED Universiti o`zining bilim va malakasi orqali insoniyat taraqiyotiga mahalliy,milliy va global miqyosida hissa qo`shishga intiluvchi salohiyatli kadrlar tayyorlashni o`z oldiga maqsad qilib qo`ygan.",card2_title:"Vazifa",card2_text:"Biz 2030-yilga qadar, O`rta Osiyodagi eng oldi o`quv muassasi bo`lishni o`z oldimizga maqsad qilib qo`yganmiz. Bizning vazifamiz shiddat bilan o`zgarib borayotgan zamon va Yangi O`zbekiston talablariga javob bera oladigan dolzarb va moslashuvchan o`quv dasturlarini o`z vaqtida taqdim etish ",card3_title:"Fidoiylik",card3_text:"Qattiy ish etikasi va mukammalikga bo`lgan intilishimizda aks etadi.",card4_title:" Ijodkorlik ",card4_text:"Yangi g`oyalar, intelektual qiziqish, tavvakal qilishga bo`lgan xohish va tadbirkorlik ruhimizda namoyon bo`ladi.",card5_title:"Moslashuvchanlik",card5_text:"Hozirgi shiddat bilan rivojlanoyotgan zamonda o`zgarishlarga moslashuvchanigimizda namoyon bo`ladi.",card6_title:"Halollik",card6_text:"Shaxsiy va kasbiy xulq-atvorda eng yuqori axloqiy me\u2019yorlarga sodiqligimiz, boshqaruv va biz qilayotgan barcha ishlarda shaffoflik va mas\u2019uliyatga sodiqligimizda namoyon bo\u2019ladi",card7_title:"Hamkorlik",card7_text:"Jamiyat, sanoat, davlat va eng muhimi, talabalarimiz bilan hamkorlikdagi ishimizda aks etadi."},symbols:{title:"Ramzlar",btn:"yuklab olish {name}",title1:"Aylana yozuv",text1:"Universitet nomi",title2:"Quyosh",text2:"logotipda chiqayotgan quyosh tasvirlangan",title3:"Qanotli Bars",text3:"Samarqand shahri haqidagi afsonalarda ko`p tilga olinadi.Shaharning ramzlaridan biri",title4:"Kitob",text4:"Ilm-fan ramzi. Har qanday universitet logotipining ajralmas qismlaridan biri.",title5:"Madrasa portali",text5:"Logotipni sharqona ruh bilan boyitadi.",title6:"Sakkiz qirrali yulduz",text6:"Sharq va Islomning ramzlaridan biri",text7:"Universitet tashkil etilgan yil",title_madhiya1:"Universitet madhiyasi",title_madhiya2:"Madhiya matni"},contact:{title:"Biz bilan bog`lanish",title2:"Buxoro psixologiya va xorijiy tillar instituti",descr2:" Buxoro psixologiya va xorijiy tillar instituti\u2013 adolatli, haqqoniy, jamiyatga foydali, global kadrlar maskani. ",linkTitle1:"Telefon 1",linkTitle2:"Telefon 2",linkTitle3:"Telegram",linkTitle4:"Facebook",linkTitle5:"Youtube",linkTitle6:"Instagram",linkTitle7:"Vebsayt"},exam:{title:"Imtihon namunalari",card1_title:"Kontrakt bo`yicha imtihonlar ",card2_title:"Grantga kirish uchun imtihon namunalari ",card1_item1:"Kirish kuni \u2013 1",card1_item2:"Biologiya Mart \u2013 2024",card1_item3:"Kimyo Mart \u2013 2024",card1_item4:"Matematika Fevral \u2013 2024",card2_item1:"Kirish kuni \u2013 1",card2_item2:"Biologiya Mart \u2013 2024",card2_item3:"Kimyo Mart \u2013 2024",card2_item4:"Matematika Fevral \u2013 2024"},ac